'use client';

import { useState } from 'react';
import { useRouter } from 'next/navigation';
import { useAuth } from '@/context/AuthContext';
import { motion } from 'framer-motion';

import BottomNav from '@/components/BottomNav';
import { HiOutlineArrowLeft } from 'react-icons/hi';

const TYPES = [
    { key: 'software', label: 'Software', icon: '💻' },
    { key: 'hardware', label: 'Hardware', icon: '🔧' },
    { key: 'non-technical', label: 'Non-Tech', icon: '🎭' },
];

const DOMAINS = [
    { key: 'healthcare', label: 'Healthcare', icon: '🏥' },
    { key: 'agriculture', label: 'Farming', icon: '🌾' },
    { key: 'travel', label: 'Travel', icon: '✈️' },
    { key: 'food', label: 'Food Tech', icon: '🍴' },
    { key: 'education', label: 'Education', icon: '📚' },
    { key: 'environment', label: 'Sustainability', icon: '🌱' },
    { key: 'finance', label: 'FinTech', icon: '💳' },
    { key: 'entertainment', label: 'Entertainment', icon: '🎮' },
];

const PACES = [
    { key: 'hackathon', label: '⚡ Hackathon Sprint', sub: 'Weekend builds' },
    { key: 'short-term', label: '🔥 Short-term', sub: '1–4 weeks' },
    { key: 'long-term', label: '🏗 Long-term', sub: '1–6 months' },
];

const COLLAB_STYLES = [
    { key: 'sync', label: 'Sync', sub: 'Daily check-ins' },
    { key: 'async', label: 'Async', sub: 'Independent work' },
    { key: 'mixed', label: 'Mixed', sub: 'Flexible' },
];

export default function ProjectCreatePage() {
    const { user, profile } = useAuth();
    const router = useRouter();

    const [name, setName] = useState('');
    const [description, setDescription] = useState('');
    const [category, setCategory] = useState('');
    const [domain, setDomain] = useState('');
    const [skillInput, setSkillInput] = useState('');
    const [desiredSkills, setDesiredSkills] = useState<string[]>([]);
    const [pace, setPace] = useState('');
    const [collabStyle, setCollabStyle] = useState('');
    const [commitmentHours, setCommitmentHours] = useState(5);
    const [teamSize, setTeamSize] = useState(3);
    const [isHackathon, setIsHackathon] = useState(false);
    const [loading, setLoading] = useState(false);
    const [enhancing, setEnhancing] = useState(false);
    const [toast, setToast] = useState<string | null>(null);

    const addSkill = () => {
        const s = skillInput.trim();
        if (s && !desiredSkills.includes(s)) setDesiredSkills((p) => [...p, s]);
        setSkillInput('');
    };

    const enhanceDescription = async () => {
        if (!description || !name) return;
        setEnhancing(true);
        try {
            const res = await fetch('/api/nim', {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({
                    action: 'enhance-description',
                    payload: { name, roughDescription: description, tags: desiredSkills, domain, category },
                }),
            });
            const { enhanced } = await res.json();
            if (enhanced) setDescription(enhanced);
        } catch { /* graceful */ }
        finally { setEnhancing(false); }
    };

    const handleSubmit = async () => {
        if (!name || !description || !category || !domain || !user || !profile) return;
        setLoading(true);
        try {
            const projectData = {
                name, description, abstract: '', category, domain,
                desiredSkills, workingStylePace: pace,
                collabStyle, commitmentHours, teamSize,
                isHackathon, isCompetition: false, status: 'open',
                ownerId: user.uid, ownerCodeName: profile.codeName,
                approvedUsers: [user.uid], interestedUsers: [], pendingUsers: [],
                tags: desiredSkills, createdAt: new Date().toISOString(),
            };

            const token = localStorage.getItem('waves_token');
            const res = await fetch('/api/projects', {
                method: 'POST',
                headers: { 'Content-Type': 'application/json', Authorization: `Bearer ${token}` },
                body: JSON.stringify(projectData),
            });
            if (!res.ok) throw new Error('Failed to create project');
            const { project: created } = await res.json();

            // Extract requirements + upsert to Pinecone
            try {
                const extractRes = await fetch('/api/nim', {
                    method: 'POST',
                    headers: { 'Content-Type': 'application/json' },
                    body: JSON.stringify({
                        action: 'extract-project',
                        payload: { name, description, tags: desiredSkills, domain, category, workingStylePace: pace, commitmentHours },
                    }),
                });
                const { extracted } = await extractRes.json();
                if (extracted && !extracted.error) {
                    await fetch(`/api/projects/${created.id || created._id}`, {
                        method: 'PUT',
                        headers: { 'Content-Type': 'application/json', Authorization: `Bearer ${token}` },
                        body: JSON.stringify({ _requirements: extracted }),
                    });
                }
                await fetch('/api/pinecone', {
                    method: 'POST',
                    headers: { 'Content-Type': 'application/json' },
                    body: JSON.stringify({
                        action: 'upsert-project',
                        payload: { id: created.id || created._id, project: projectData },
                    }),
                });
            } catch { /* graceful */ }

            setToast('Project created! ✓');
            setTimeout(() => router.push(`/projects/${created.id || created._id}`), 1200);
        } catch (err) {
            console.error(err);
            setToast('Error creating project');
        } finally { setLoading(false); }
    };

    return (
        <div className="min-h-screen bg-white pb-20">
            {/* Header */}
            <div className="sticky top-0 bg-white/90 backdrop-blur-lg z-10 border-b border-gray-100">
                <div className="max-w-lg mx-auto px-6 py-4 flex items-center gap-3">
                    <button
                        onClick={() => router.back()}
                        className="w-8 h-8 flex items-center justify-center rounded-full hover:bg-gray-100 transition-colors"
                    >
                        <HiOutlineArrowLeft className="text-lg" />
                    </button>
                    <h1 className="text-lg font-bold tracking-tight">New Project</h1>
                </div>
            </div>

            <div className="max-w-lg mx-auto px-6 py-6 space-y-5 overflow-y-auto pb-32" style={{ maxHeight: 'calc(100dvh - 80px)' }}>
                {/* Name */}
                <div>
                    <label className="text-xs font-bold uppercase tracking-widest text-gray-400 mb-1.5 block">
                        Project Name
                    </label>
                    <input
                        type="text"
                        placeholder="e.g. Smart Campus Guide"
                        value={name}
                        onChange={(e) => setName(e.target.value)}
                        className="w-full px-4 py-3 border border-gray-200 rounded-xl text-sm focus:border-black transition-colors"
                    />
                </div>

                {/* Description */}
                <div>
                    <div className="flex items-center justify-between mb-1.5">
                        <label className="text-xs font-bold uppercase tracking-widest text-gray-400">
                            Description
                        </label>
                        <motion.button
                            whileTap={{ scale: 0.95 }}
                            onClick={enhanceDescription}
                            disabled={enhancing || !description}
                            className="flex items-center gap-1 px-3 py-1.5 bg-violet-100 text-violet-700 text-[10px] font-bold rounded-full hover:bg-violet-200 transition-colors disabled:opacity-50"
                        >
                            {enhancing ? (
                                <>
                                    <motion.div
                                        animate={{ rotate: 360 }}
                                        transition={{ repeat: Infinity, duration: 1, ease: 'linear' }}
                                        className="w-3 h-3 border border-violet-500 border-t-transparent rounded-full"
                                    />
                                    Enhancing...
                                </>
                            ) : (
                                <>✦ Enhance with AI</>
                            )}
                        </motion.button>
                    </div>
                    <textarea
                        placeholder="What are you building? What problem does it solve?"
                        value={description}
                        onChange={(e) => setDescription(e.target.value)}
                        rows={3}
                        className="w-full px-4 py-3 border border-gray-200 rounded-xl text-sm focus:border-black transition-colors resize-none"
                    />
                </div>

                {/* Type */}
                <div>
                    <label className="text-xs font-bold uppercase tracking-widest text-gray-400 mb-2 block">Type</label>
                    <div className="grid grid-cols-3 gap-2">
                        {TYPES.map((t) => (
                            <motion.button
                                key={t.key}
                                whileTap={{ scale: 0.95 }}
                                onClick={() => setCategory(t.key)}
                                className={`p-4 rounded-xl border text-center transition-all ${
                                    category === t.key
                                        ? 'border-black bg-black text-white'
                                        : 'border-gray-200 hover:border-gray-400'
                                }`}
                            >
                                <span className="text-xl block mb-1">{t.icon}</span>
                                <span className="text-xs font-semibold">{t.label}</span>
                            </motion.button>
                        ))}
                    </div>
                </div>

                {/* Domain */}
                <div>
                    <label className="text-xs font-bold uppercase tracking-widest text-gray-400 mb-2 block">Domain</label>
                    <div className="grid grid-cols-4 gap-2">
                        {DOMAINS.map((d) => (
                            <motion.button
                                key={d.key}
                                whileTap={{ scale: 0.95 }}
                                onClick={() => setDomain(d.key)}
                                className={`p-3 rounded-xl border text-center transition-all ${
                                    domain === d.key
                                        ? 'border-black bg-black text-white'
                                        : 'border-gray-200 hover:border-gray-400'
                                }`}
                            >
                                <span className="text-lg block mb-0.5">{d.icon}</span>
                                <span className="text-[10px] font-semibold">{d.label}</span>
                            </motion.button>
                        ))}
                    </div>
                </div>

                {/* Desired Skills */}
                <div>
                    <label className="text-xs font-bold uppercase tracking-widest text-gray-400 mb-1.5 block">Skills Needed</label>
                    <div className="flex gap-2 mb-2">
                        <input
                            type="text"
                            placeholder="e.g. React, Arduino, ML..."
                            value={skillInput}
                            onChange={(e) => setSkillInput(e.target.value)}
                            onKeyDown={(e) => e.key === 'Enter' && addSkill()}
                            className="flex-1 px-4 py-3 border border-gray-200 rounded-xl text-sm focus:border-black transition-colors"
                        />
                        <motion.button
                            whileTap={{ scale: 0.95 }}
                            onClick={addSkill}
                            className="px-4 py-3 bg-black text-white rounded-xl text-sm font-bold"
                        >
                            +
                        </motion.button>
                    </div>
                    <div className="flex flex-wrap gap-1.5">
                        {desiredSkills.map((s) => (
                            <span
                                key={s}
                                onClick={() => setDesiredSkills((p) => p.filter((x) => x !== s))}
                                className="px-3 py-1.5 bg-gray-100 text-xs font-medium rounded-full cursor-pointer hover:bg-red-50 hover:text-red-600 transition-colors"
                            >
                                {s} ✕
                            </span>
                        ))}
                    </div>
                </div>

                {/* Pace */}
                <div>
                    <label className="text-xs font-bold uppercase tracking-widest text-gray-400 mb-2 block">Working Pace</label>
                    <div className="space-y-2">
                        {PACES.map((p) => (
                            <motion.button
                                key={p.key}
                                whileTap={{ scale: 0.98 }}
                                onClick={() => setPace(p.key)}
                                className={`w-full p-4 rounded-xl border text-left transition-all flex justify-between items-center ${
                                    pace === p.key
                                        ? 'border-black bg-black text-white'
                                        : 'border-gray-200 hover:border-gray-400'
                                }`}
                            >
                                <span className="text-sm font-semibold">{p.label}</span>
                                <span className={`text-xs ${pace === p.key ? 'text-gray-300' : 'text-gray-400'}`}>{p.sub}</span>
                            </motion.button>
                        ))}
                    </div>
                </div>

                {/* Collab style */}
                <div>
                    <label className="text-xs font-bold uppercase tracking-widest text-gray-400 mb-2 block">Collaboration Style</label>
                    <div className="grid grid-cols-3 gap-2">
                        {COLLAB_STYLES.map((c) => (
                            <motion.button
                                key={c.key}
                                whileTap={{ scale: 0.95 }}
                                onClick={() => setCollabStyle(c.key)}
                                className={`p-3 rounded-xl border text-center transition-all ${
                                    collabStyle === c.key
                                        ? 'border-black bg-black text-white'
                                        : 'border-gray-200 hover:border-gray-400'
                                }`}
                            >
                                <div className="text-sm font-semibold">{c.label}</div>
                                <div className={`text-[10px] mt-0.5 ${collabStyle === c.key ? 'text-gray-300' : 'text-gray-400'}`}>{c.sub}</div>
                            </motion.button>
                        ))}
                    </div>
                </div>

                {/* Commitment + Team size */}
                <div className="grid grid-cols-2 gap-3">
                    <div>
                        <label className="text-xs font-bold uppercase tracking-widest text-gray-400 mb-1.5 block">Hours/Week</label>
                        <input
                            type="number"
                            min={1}
                            max={60}
                            value={commitmentHours}
                            onChange={(e) => setCommitmentHours(+e.target.value)}
                            className="w-full px-4 py-3 border border-gray-200 rounded-xl text-sm focus:border-black transition-colors"
                        />
                    </div>
                    <div>
                        <label className="text-xs font-bold uppercase tracking-widest text-gray-400 mb-1.5 block">Team Size</label>
                        <input
                            type="number"
                            min={2}
                            max={20}
                            value={teamSize}
                            onChange={(e) => setTeamSize(+e.target.value)}
                            className="w-full px-4 py-3 border border-gray-200 rounded-xl text-sm focus:border-black transition-colors"
                        />
                    </div>
                </div>

                {/* Hackathon toggle */}
                <div className="flex items-center gap-3">
                    <button
                        onClick={() => setIsHackathon((p) => !p)}
                        className={`flex-1 py-3 rounded-xl text-sm font-semibold transition-all ${
                            isHackathon ? 'bg-black text-white' : 'border border-gray-200 text-gray-500'
                        }`}
                    >
                        {isHackathon ? '⚡ Hackathon Project' : 'Hackathon Project?'}
                    </button>
                </div>

                <motion.button
                    whileTap={{ scale: 0.98 }}
                    disabled={!name || !description || !category || !domain || loading}
                    onClick={handleSubmit}
                    className="w-full py-3.5 bg-black text-white rounded-xl text-sm font-semibold disabled:opacity-40 transition-opacity"
                >
                    {loading ? 'Creating...' : 'Post Project →'}
                </motion.button>
            </div>

            {/* Toast */}
            {toast && (
                <motion.div
                    initial={{ opacity: 0, y: 20 }}
                    animate={{ opacity: 1, y: 0 }}
                    exit={{ opacity: 0 }}
                    className="fixed bottom-24 left-1/2 -translate-x-1/2 px-6 py-3 bg-black text-white text-sm font-semibold rounded-full shadow-lg z-50"
                >
                    {toast}
                </motion.div>
            )}
            <BottomNav />
        </div>
    );
}
